$ErrorActionPreference = "Stop"

# ============================================================
# CONFIG
# ============================================================

$MainDir            = "C:\Windows\System32\Acceleron"
$BaseDir            = Join-Path $MainDir "Winget"
$CertDir            = Join-Path $MainDir "Certificate"

$PolicyExePath      = Join-Path $BaseDir "winget.exe"
$CertPath           = Join-Path $CertDir "GainwellWallpaper.cer"

$PolicyTaskName     = "Winget Upgrade Policy"

$PinnedThumbprint   = "ECACA66CD84B620E80C8329A253DE85149666D6E"

$TriggerInterval    = 5
$IsSystem           = ([Security.Principal.WindowsIdentity]::GetCurrent().IsSystem)
$IsAdmin            = ([Security.Principal.WindowsPrincipal] `
                      [Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)

# ============================================================
# ENSURE BASE DIRECTORY
# ============================================================

# Create base directory if not exists
if (-not (Test-Path $BaseDir)) {
    New-Item -Path $BaseDir -ItemType Directory -Force | Out-Null
}

# Create certificate directory if not exists
if (-not (Test-Path $CertDir)) {
    New-Item -Path $CertDir -ItemType Directory -Force | Out-Null
}

# ============================================================
# CLEAN OLD TASKS (SAFE)
# ============================================================

Get-ScheduledTask $PolicyTaskName -ErrorAction SilentlyContinue | Unregister-ScheduledTask -Confirm:$false

Remove-Item $PolicyExePath  -Force -ErrorAction SilentlyContinue
Remove-Item $CertPath -Force -ErrorAction SilentlyContinue
Remove-Item "C:\ProgramData\winget-upgrade.ps1" -Force -ErrorAction SilentlyContinue

# ============================================================
# EMBEDDED BINARIES (BASE64)
# ============================================================

$CertBase64 = @'

'@

$WingetExeBase64 = @'

'@

# ============================================================
# DECODE EXEs
# ============================================================

$PolicyExeBytes = [Convert]::FromBase64String($WingetExeBase64)

# ============================================================
# WRITE + TRUST CERTIFICATE (SYSTEM ONLY)
# ============================================================

if ($IsSystem -or $IsAdmin) {

    if (-not (Test-Path $CertPath)) {
        [IO.File]::WriteAllBytes(
            $CertPath,
            [Convert]::FromBase64String($CertBase64)
        )
    }

    foreach ($store in @(
        "Root",
        "TrustedPublisher"
    )) {
        if (-not (certutil -store $store | Select-String $PinnedThumbprint)) {
            & certutil.exe -addstore $store $CertPath | Out-Null
        }
    }
}

# ============================================================
# WRITE POLICY SCRIPT (SYSTEM)
# ============================================================
$WritePolicyExe = $true

if (Test-Path $PolicyExePath) {

    $Sig = Get-AuthenticodeSignature $PolicyExePath

    if (
        $Sig.SignerCertificate -and
        $Sig.SignerCertificate.Thumbprint -eq $PinnedThumbprint
    ) {
        $WritePolicyExe = $false
    }
}

if ($WritePolicyExe) {

    [IO.File]::WriteAllBytes($PolicyExePath, $PolicyExeBytes)

    Start-Sleep 2
    $Sig = Get-AuthenticodeSignature $PolicyExePath

    if (
        -not $Sig.SignerCertificate -or
        $Sig.SignerCertificate.Thumbprint -ne $PinnedThumbprint -or
        $Sig.Status -in @('HashMismatch','NotSigned')
    ) {
        throw "Appblocker.exe signature validation failed"
    }
}

# ============================================================
# SCHEDULED TASK: POLICY (SYSTEM)
# ============================================================

# Random time (9 AM – 5 PM)
$hour = Get-Random -Minimum 9 -Maximum 17
$minute = Get-Random -Minimum 0 -Maximum 59

$startTime = (Get-Date).Date.AddHours($hour).AddMinutes($minute)

if ($startTime -lt (Get-Date)) {
    $startTime = $startTime.AddDays(1)
}

# Scheduled Task Action
$action = New-ScheduledTaskAction -Execute "$PolicyExePath"

# Trigger
$trigger = New-ScheduledTaskTrigger -Daily -At $startTime

# Settings
$settings = New-ScheduledTaskSettingsSet `
    -StartWhenAvailable `
    -AllowStartIfOnBatteries `
    -DontStopIfGoingOnBatteries `
	-RunOnlyIfNetworkAvailable `
    -Hidden `
	-ExecutionTimeLimit (New-TimeSpan -Days 0)

# Register Task (SYSTEM, no UI)
$null = Register-ScheduledTask -TaskName $PolicyTaskName `
    -Action $action `
    -Trigger $trigger `
    -Settings $settings `
    -User "SYSTEM" `
    -RunLevel Highest `
    -Force

Write-Host "Winget Policy Updated"
Write-Host "Scheduled Time : $($startTime.ToString('dd/MM/yyyy HH:mm'))"